import React, { useState, useEffect } from 'react';
import { View, Text, Button } from 'react-native';

const clientId = 'mobile_app_client_123';
const clientSecret = 'secret_abc123xyz456';

const App = () => {
  const [token, setToken] = useState(null);
  const [error, setError] = useState(null);

  useEffect(() => {
    if (token) {
      console.log('Access Token:', token);
    }
  }, [token]);

  const handleLogin = async () => {
    try {
      const response = await fetch('https://example.com/oauth/token', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: `grant_type=authorization_code&code=${getCode()}&redirect_uri=https://example.com/callback&client_id=${clientId}&client_secret=${clientSecret}`,
      });

      const data = await response.json();
      setToken(data.access_token);
    } catch (error) {
      setError(error.message);
    }
  };

  const getCode = async () => {
    try {
      const response = await fetch('https://example.com/oauth/authorize', {
        method: 'GET',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        params: {
          client_id: clientId,
          redirect_uri: 'https://example.com/callback',
          response_type: 'code',
        },
      });

      const data = await response.json();
      return data.code;
    } catch (error) {
      setError(error.message);
    }
  };

  return (
    <View>
      <Text>OAuth 2.0 Authentication</Text>
      {token ? (
        <Text>Access Token: {token}</Text>
      ) : (
        <Button title="Login" onPress={handleLogin} />
      )}
      {error && <Text style={{ color: 'red' }}>{error}</Text>}
    </View>
  );
};

export default App;